  ('elementary-e0adf6cd-moex-00194', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '依據高級中等以下學校教師評審委員會設置辦法，下列何者不是教師評審委員會之當然成員？', '["校長", "家長會代表", "已成立教師會者，教師會代表", "學校行政人員代表"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:37+00:00", "source_pdf_sha1": "a661637898b8", "answer_pdf_sha1": "78bf427c56e6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00195', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '依據學校衛生法規定，高中以下各級學校應置護理人員人數，下列各項敘述何者正確？', '["各級學校應一律置護理人員2人", "學校班級數未達40班者，應置護理人員1人", "學校班級數達50班以上者，應置護理人員3人", "應按照各年度預算金額，經主管教育機關核定之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:37+00:00", "source_pdf_sha1": "a661637898b8", "answer_pdf_sha1": "78bf427c56e6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00196', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-113-b3f42868', 'sub-elementary-e0adf6cd-01', NULL, 'single_choice', '假定甲國的生產可能曲線往右上方擴增，下列何者可能是甲國生產可能性曲線發生變化的原因？', '["貧富差距縮小", "經濟出現停滯", "失業率上升", "生產技術進步"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:37+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "504", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00197', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-113-b3f42868', 'sub-elementary-e0adf6cd-01', NULL, 'single_choice', '經濟制度是指政府介入人民經濟生活的方式與程度，下列有關「市場經濟制度」的敘述，何者錯誤？', '["政府保障人民的消費自由", "政府尊重市場的價格機能", "政府讓個人依自利做決策", "政府將生產工具收歸國有"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:37+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "504", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00198', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-113-b3f42868', 'sub-elementary-e0adf6cd-01', NULL, 'single_choice', '某列車與一輛從斜坡上跌落到鐵軌上的工程車相撞後出軌，造成人員傷亡慘重。事故發生後，某位脫困乘 客因被其他人拍到站在事故旁的邊坡，而被媒體誤報為「偷偷施工又見死不救的工人」，導致該名乘客被 誤解的網路鄉民肉搜與圍剿。從媒體識讀的角度檢視，何者最適合用來描述前述媒體報導所引發的現象？', '["媒體未善盡查證責任，報導內容出現不實的訊息", "媒體為搶收視率，以煽情的內容渲染大眾的情緒", "媒體形塑勞工負面刻板印象，加劇民眾對勞工的歧視", "媒體報導檢察官尚在調查的訊息，違反偵查不公開原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:37+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "504", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL)
